<?php
namespace App\Domain\Admin\Content;use App\Domain\Equipment\EquippableItemValidator;use App\Domain\Loot\LootConfigurationValidator;use App\Domain\WorldCatalog\CatalogStatus;use App\Domain\WorldCatalog\WorldCatalogValidator;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use App\Models\Zone;use App\Models\ZoneMonster;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class ContentAdminService{private $catalog;private $items;private $loot;public function __construct(WorldCatalogValidator $catalog,EquippableItemValidator $items,LootConfigurationValidator $loot){$this->catalog=$catalog;$this->items=$items;$this->loot=$loot;}public function saveItem(array $data,Item $item=null){return DB::transaction(function()use($data,$item){$model=$item?:new Item();$data['code']=$this->catalog->normalizeCode($data['code']);$candidate=new Item($data);$this->catalog->assertItemType($candidate->item_type);$this->catalog->assertItemRarity($candidate->rarity);$this->catalog->assertStatus($candidate->status);$this->catalog->assertItemStack((bool)$candidate->is_stackable,$candidate->max_stack);$this->items->equipmentType($candidate);$model->fill($data);$model->save();return$model;});}public function deactivateItem(Item $item){$item->update(['status'=>CatalogStatus::INACTIVE]);}public function saveMonster(array $data,Monster $monster=null){return DB::transaction(function()use($data,$monster){$this->catalog->assertStatus($data['status']);$data['code']=$this->catalog->normalizeCode($data['code']);if((int)$data['gold_min']>(int)$data['gold_max'])throw new InvalidArgumentException('Gold minimum cannot exceed maximum.');$model=$monster?:new Monster();$model->fill($data);$model->save();return$model;});}public function deactivateMonster(Monster $monster){$monster->update(['status'=>CatalogStatus::INACTIVE]);}public function saveZone(array $data,Zone $zone=null){return DB::transaction(function()use($data,$zone){$this->catalog->assertStatus($data['status']);$this->catalog->assertZoneType($data['zone_type']);$this->catalog->assertLevelRange($data['recommended_level_min'],$data['recommended_level_max']);$data['code']=$this->catalog->normalizeCode($data['code']);$model=$zone?:new Zone();$model->fill($data);$model->save();return$model;});}public function deactivateZone(Zone $zone){$zone->update(['status'=>CatalogStatus::INACTIVE]);}public function saveZoneMonster(Zone $zone,Monster $monster,array $data){return DB::transaction(function()use($zone,$monster,$data){$this->catalog->assertZoneMonster($data['weight'],$data['minimum_character_level'],$data['maximum_character_level']);$this->catalog->assertStatus($data['status']);$row=ZoneMonster::where('zone_id',$zone->id)->where('monster_id',$monster->id)->first();if(!$row)$row=new ZoneMonster(['zone_id'=>$zone->id,'monster_id'=>$monster->id]);$row->fill($data);$row->save();return$row;});}public function removeZoneMonster(Zone $zone,Monster $monster){ZoneMonster::where('zone_id',$zone->id)->where('monster_id',$monster->id)->delete();}public function saveLoot(Monster $monster,Item $item,array $data,MonsterLootEntry $entry=null){return DB::transaction(function()use($monster,$item,$data,$entry){$this->loot->validate($monster,$item,(int)$data['drop_chance_basis_points'],(int)$data['minimum_quantity'],(int)$data['maximum_quantity'],$data['status'],$entry);$model=$entry?:new MonsterLootEntry(['monster_id'=>$monster->id,'item_id'=>$item->id]);$model->fill($data);$model->save();return$model;});}public function deactivateLoot(MonsterLootEntry $entry){$entry->update(['status'=>CatalogStatus::INACTIVE]);}}
